@js:
// 从章节URL中提取小说ID和章节ID
let url = baseUrl;
let match = url.match(/tingshu\/(\d+)\/(\d+)\.html/);
if (!match) {
    return '';
}
let nid = match[1];
let cid = match[2];

// 构造播放器URL并访问
let playerUrl = 'https://www.qdysw.com/player.html?nid=' + nid + '&cid=' + cid + '&site=16';
let playerHtml = java.ajax(playerUrl);

// 从播放器页面提取音频地址
let audioMatch = playerHtml.match(/mp3:'(https?:\/\/[^']+\.mp3)'/);
if (audioMatch && audioMatch[1]) {
    return audioMatch[1];
}
return '';
